// Federations ingest — find-or-create into PocketBase (no upsert in PB).
// Config via n8n env vars (keep secrets out of the committed workflow):
//   POCKETBASE_URL, POCKETBASE_ADMIN_EMAIL, POCKETBASE_ADMIN_PASSWORD
// Input: the parsed VIS XML from the previous node ($json.Federations.Federation).

const PB_URL = ($env.POCKETBASE_URL || 'http://localhost:8090').replace(/\/+$/, '');
const PB_EMAIL = $env.POCKETBASE_ADMIN_EMAIL;
const PB_PASSWORD = $env.POCKETBASE_ADMIN_PASSWORD;
const VIS_URL = 'https://www.fivb.org/Vis2009/XmlRequest.asmx';

if (!PB_EMAIL || !PB_PASSWORD) {
  throw new Error('Set POCKETBASE_ADMIN_EMAIL and POCKETBASE_ADMIN_PASSWORD as n8n env vars.');
}

// Rescrape flag (header on the webhook call). For federations the pass is identical;
// the flag is plumbed for symmetry / future "skip recently-scraped" logic.
const headers = ($('Webhook').first().json.headers) || {};
const rescrape = String(headers.rescrape || headers.Rescrape || '').toLowerCase() === 'true';

// Pull the parsed Federation array (XML node nests attributes under `$`).
const root = $input.first().json;
let feds = root && root.Federations && root.Federations.Federation;
if (!feds) feds = [];
if (!Array.isArray(feds)) feds = [feds];

const attr = (f, ...names) => {
  const a = (f && f.$) || {};
  for (const n of names) {
    const v = a[n];
    if (v != null && String(v).trim() !== '') return String(v).trim();
  }
  return '';
};
const normUrl = (u) => {
  u = (u || '').trim();
  if (!u) return '';
  return /^https?:\/\//i.test(u) ? u : 'https://' + u;
};

// Authenticate as PocketBase superuser.
const auth = await this.helpers.httpRequest({
  method: 'POST',
  url: PB_URL + '/api/collections/_superusers/auth-with-password',
  body: { identity: PB_EMAIL, password: PB_PASSWORD },
  json: true,
});
const pbHeaders = { Authorization: auth.token };

const findByCode = async (code) => {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: PB_URL + '/api/collections/federations/records',
    qs: { filter: "(fivb_code='" + code + "')", perPage: 1 },
    headers: pbHeaders,
    json: true,
  });
  return (res.items && res.items[0]) || null;
};

let created = 0, updated = 0, failed = 0;
const errors = [];
const now = new Date().toISOString();

for (const f of feds) {
  const code = attr(f, 'Code');
  if (!code) continue;

  const payload = {
    fivb_code: code,
    name: attr(f, 'Name'),
    country: attr(f, 'TeamName'),
    confederation: attr(f, 'ConfederationCode'),
    website_url: normUrl(attr(f, 'WebSite', 'Website')),
    president: attr(f, 'NamePresident'),
    general_secretary: attr(f, 'NameGeneralSecretary'),
    email: attr(f, 'eMailAddress', 'EmailAddress'),
    phone: attr(f, 'PhoneNo'),
    source_url: VIS_URL,
    last_scraped: now,
  };

  try {
    const existing = await findByCode(code);
    if (existing) {
      // Leave `status` untouched (it tracks Phase 2 club-discovery state).
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: PB_URL + '/api/collections/federations/records/' + existing.id,
        headers: pbHeaders, body: payload, json: true,
      });
      updated++;
    } else {
      try {
        await this.helpers.httpRequest({
          method: 'POST',
          url: PB_URL + '/api/collections/federations/records',
          headers: pbHeaders, body: Object.assign({ status: 'new' }, payload), json: true,
        });
        created++;
      } catch (e) {
        // Benign unique-constraint race -> someone created it; update instead.
        const again = await findByCode(code);
        if (again) {
          await this.helpers.httpRequest({
            method: 'PATCH',
            url: PB_URL + '/api/collections/federations/records/' + again.id,
            headers: pbHeaders, body: payload, json: true,
          });
          updated++;
        } else {
          throw e;
        }
      }
    }
  } catch (e) {
    failed++;
    if (errors.length < 10) errors.push({ code, message: (e && e.message) || String(e) });
  }
}

return [{ json: { ok: failed === 0, total: feds.length, created, updated, failed, rescrape, errors } }];
